/**
 * #### Spacing
 *
 * Use these tokens for adding margin between elements or padding within containers.
 *
 * Just because a spacing token is equal to a pixel value you may need, it does not mean it's appropriate to
 * use the spacing variables.
 *
 * @category dimension
 * @previewType spacing
 */
declare const spacing: {
    spacingXSmall: string;
    spacingSmall: string;
    spacingMedium: string;
    spacingLarge: string;
    spacingXLarge: string;
    spacingXXLarge: string;
    spacingXXXLarge: string;
};
/**
 * #### Measures
 *
 * @category dimension
 * @previewType spacing
 */
declare const measures: {
    borderRadius: string;
    inputBorderWidth: string;
    inputHeight: string;
};
declare const spacingSizing: {
    borderRadius: string;
    inputBorderWidth: string;
    inputHeight: string;
    spacingXSmall: string;
    spacingSmall: string;
    spacingMedium: string;
    spacingLarge: string;
    spacingXLarge: string;
    spacingXXLarge: string;
    spacingXXXLarge: string;
};
type Spacing = typeof spacing;
type Measures = typeof measures;
type SpacingSizing = typeof spacingSizing;
export type { Spacing, Measures, SpacingSizing };
export default spacingSizing;
